class MicroWebSocket:
    def __init__(self, host='0.0.0.0', port=80, max_clients=1):
        self.host = host
        self.port = port
        self.max_clients = max_clients
        self.clients = []
        self.on_message = None
        self.on_connect = None
        self.on_disconnect = None
        self.server_sock = None

    def _handle_client(self, conn, addr):
        print(f"Client connected from {addr}")
        try:
            # WebSocket Handshake
            request = conn.recv(1024).decode()
            if "Upgrade: websocket" not in request or "Connection: Upgrade" not in request:
                conn.send(b"HTTP/1.1 400 Bad Request\r\n\r\n")
                conn.close()
                print(f"Client {addr} did not send a WebSocket upgrade request.")
                return

            key_start = request.find("Sec-WebSocket-Key: ") + len("Sec-WebSocket-Key: ")
            key_end = request.find("\r\n", key_start)
            sec_websocket_key = request[key_start:key_end]

            import ubinascii
            import hashlib
            magic_string = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
            combined = sec_websocket_key + magic_string
            sha1 = hashlib.sha1(combined.encode()).digest()
            sec_websocket_accept = ubinascii.b2a_base64(sha1).decode().strip()

            response = (
                b"HTTP/1.1 101 Switching Protocols\r\n"
                b"Upgrade: websocket\r\n"
                b"Connection: Upgrade\r\n"
                b"Sec-WebSocket-Accept: " + sec_websocket_accept.encode() + b"\r\n\r\n"
            )
            conn.send(response)
            print(f"WebSocket handshake complete for {addr}")

            self.clients.append(conn)
            if self.on_connect:
                self.on_connect(conn, addr)

            while True:
                header = conn.recv(2)
                if not header:
                    break

                fin = (header[0] >> 7) & 0x1
                opcode = header[0] & 0x0F
                
                # We only care about text frames (opcode 1) for now
                if opcode == 0x1: # Text frame
                    mask_and_len = header[1]
                    mask_bit = (mask_and_len >> 7) & 0x1
                    payload_len = mask_and_len & 0x7F

                    if payload_len == 126:
                        ext_payload_len = conn.recv(2)
                        payload_len = int.from_bytes(ext_payload_len, 'big')
                    elif payload_len == 127:
                        # We don't expect such large frames on ESP32, but for completeness
                        ext_payload_len = conn.recv(8)
                        payload_len = int.from_bytes(ext_payload_len, 'big')

                    if mask_bit:
                        mask = conn.recv(4)
                    
                    data = conn.recv(payload_len)

                    if mask_bit:
                        decoded_data = bytearray(len(data))
                        for i in range(len(data)):
                            decoded_data[i] = data[i] ^ mask[i % 4]
                        message = decoded_data.decode('utf-8')
                    else:
                        message = data.decode('utf-8')
                    
                    if self.on_message:
                        self.on_message(conn, message)

                elif opcode == 0x8: # Connection Close frame
                    print(f"Client {addr} sent close frame.")
                    break
                elif opcode == 0x9: # Ping frame
                    # Respond with Pong frame
                    self.send(conn, b'', opcode=0xA)
                    print(f"Received PING from {addr}")
                else:
                    # Other opcodes (binary, continuation, etc.) are ignored for simplicity
                    # Consume the rest of the frame to avoid blocking
                    mask_and_len = header[1]
                    payload_len = mask_and_len & 0x7F
                    if payload_len == 126:
                        conn.recv(2)
                    elif payload_len == 127:
                        conn.recv(8)
                    if (mask_and_len >> 7) & 0x1:
                        conn.recv(4)
                    conn.recv(payload_len)

        except Exception as e:
            print(f"Error handling client {addr}: {e}")
        finally:
            if conn in self.clients:
                self.clients.remove(conn)
            if self.on_disconnect:
                self.on_disconnect(conn, addr)
            conn.close()
            print(f"Client {addr} disconnected.")

    def send(self, client_sock, message, opcode=0x1):
        if not client_sock:
            return

        if isinstance(message, str):
            message = message.encode('utf-8')
        elif not isinstance(message, bytes):
            raise TypeError("Message must be string or bytes")

        length = len(message)
        
        # Frame header
        # FIN=1, RSV=0,0,0, Opcode (0x1 for text, 0x2 for binary, 0x8 for close, 0x9 for ping, 0xA for pong)
        header = bytearray([0x80 | opcode])

        if length < 126:
            header.append(length)
        elif length < 2**16:
            header.append(126)
            header.extend(length.to_bytes(2, 'big'))
        else:
            header.append(127)
            header.extend(length.to_bytes(8, 'big'))

        try:
            client_sock.send(header + message)
        except OSError as e:
            print(f"Error sending message: {e}")
            # Client disconnected, will be handled by the _handle_client loop
            
    def broadcast(self, message):
        for client_sock in list(self.clients): # Iterate over a copy to avoid issues if clients disconnect
            self.send(client_sock, message)

    def start(self):
        self.server_sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_sock.bind((self.host, self.port))
        self.server_sock.listen(self.max_clients)
        print(f"WebSocket server started on ws://{self.host}:{self.port}")

        while True:
            try:
                conn, addr = self.server_sock.accept()
                _thread.start_new_thread(self._handle_client, (conn, addr))
            except Exception as e:
                print(f"Server accept error: {e}")
                time.sleep(1) # Prevent busy loop on errors

